import{j as e}from"./vendor-Dh_dlHsl.js";import{C as t,A as s,N as n,E as i,W as a,P as o}from"./subject-01-thinking-in-agents-BIrOrpH9.js";const x={id:"integration",title:"Integration Patterns",description:"Embedding agents into real environments — IDE bridges, remote execution, and plugin architectures.",icon:"🔗",colorHex:"#e04e17",difficulty:"advanced",estimatedHours:10,prerequisites:["protocols","workflows"],chapters:[{id:"c1-ide-integration",title:"IDE Integration",description:"Connecting agents to code editors through bidirectional bridges.",difficulty:"advanced",estimatedMinutes:80,sections:[{id:"s1-bridge-pattern",title:"The Bridge Pattern",description:"Bidirectional communication with editors — messages flowing both ways.",difficulty:"advanced",readingMinutes:12},{id:"s2-permission-delegation",title:"Permission Delegation",description:"Letting the host environment decide — the IDE as permission authority.",difficulty:"advanced",readingMinutes:10},{id:"s3-inline-vs-external",title:"Inline vs External",description:"Agents inside the editor vs alongside it — tradeoffs of each approach.",difficulty:"intermediate",readingMinutes:10},{id:"s4-interactive-sessions",title:"Interactive Sessions",description:"REPL-style agent conversations — interactive loops within an editor.",difficulty:"advanced",readingMinutes:10}]},{id:"c2-remote",title:"Remote and Distributed Agents",description:"Agents running across network boundaries — tunneling, adapters, and coordination.",difficulty:"advanced",estimatedMinutes:80,sections:[{id:"s1-remote-machines",title:"Agents on Remote Machines",description:"Running across network boundaries — why locality matters for agents.",difficulty:"advanced",readingMinutes:10},{id:"s2-secure-tunneling",title:"Secure Tunneling",description:"SSH, teleport, and direct connections — secure access to remote environments.",difficulty:"advanced",readingMinutes:12},{id:"s3-message-translation",title:"Message Translation",description:"Adapting protocols between systems — format conversion at the boundary.",difficulty:"advanced",readingMinutes:10},{id:"s4-cross-machine",title:"Cross-Machine Coordination",description:"Distributed agent teams — multiple machines working as one.",difficulty:"advanced",readingMinutes:12}]},{id:"c3-extensibility",title:"Extensibility",description:"Plugin architecture — extending agents after deployment.",difficulty:"advanced",estimatedMinutes:80,sections:[{id:"s1-plugin-architecture",title:"Plugin Architecture",description:"Extending agents after deployment — the framework for third-party capabilities.",difficulty:"advanced",readingMinutes:12},{id:"s2-discovery-loading",title:"Discovery and Loading",description:"Finding plugins at runtime — auto-discovery, registration, and initialization.",difficulty:"advanced",readingMinutes:10},{id:"s3-plugins-add-capabilities",title:"Plugins That Add Capabilities",description:"Tools, commands, and behaviors — what plugins can contribute.",difficulty:"advanced",readingMinutes:10},{id:"s4-plugin-lifecycle",title:"Managing Plugin Lifecycle",description:"Updates, conflicts, and deprecation — keeping plugins healthy over time.",difficulty:"advanced",readingMinutes:10}]}]};function r(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"The Bridge Pattern"}),e.jsx("p",{children:"When an agent needs to operate inside a developer's environment — reading files, running commands, understanding project structure — it cannot simply connect directly to every tool and editor on its own. A mediating layer is required. This mediating layer is called a bridge."}),e.jsx(t,{title:"The IDE Bridge",number:"Concept 11.1",children:`A bridge is a process that sits between the agent and the developer's environment. It translates the agent's abstract requests — "read this file," "run this test" — into concrete operations within the specific IDE or editor being used. The bridge owns the knowledge of how to talk to the environment; the agent only needs to know how to talk to the bridge.`}),e.jsx("p",{children:"This separation of concerns is deliberate. The agent should not need to know whether it is operating inside VS Code, a JetBrains IDE, or a terminal. By delegating environment-specific knowledge to the bridge, the same agent logic can work across many different host environments without modification."}),e.jsx(s,{title:"The Embassy Interpreter",children:"An ambassador does not need to speak every language of every country they visit. They bring an interpreter who handles the local communication. The bridge plays the role of that interpreter — fluent in the language of the host environment, converting the agent's standardized requests into whatever the environment expects."}),e.jsx(n,{title:"Bridges Are Thin by Design",type:"tip",children:"A well-designed bridge does as little logic as possible. Its job is translation, not decision-making. The more behavior a bridge accumulates, the harder it becomes to reason about what the agent is actually doing. Keep bridges thin, testable, and focused purely on the translation task."}),e.jsx(i,{title:"Exercises",exercises:[{id:"bp-1",difficulty:"beginner",question:"Why is it beneficial to separate the bridge from the agent rather than having the agent directly invoke IDE-specific APIs?",hint:"Think about what changes when the IDE changes.",solution:"If the agent calls IDE-specific APIs directly, every change in the IDE requires changing the agent. With a bridge, only the bridge needs updating. The agent remains stable while bridges for different environments can evolve independently. This also makes testing easier — the agent can be tested with a mock bridge that simulates an environment without a real IDE present."},{id:"bp-2",difficulty:"intermediate",question:'A bridge is said to be "thin by design." What risks arise when a bridge becomes thick — accumulating significant logic of its own?',hint:"Consider where bugs would live and how testing would work.",solution:"A thick bridge becomes a second agent — making decisions that should belong to the agent. Behavior becomes split across two places, making debugging difficult. Tests must now cover bridge logic separately, and subtle differences between what the agent intends and what the bridge executes can cause hard-to-trace errors. The agent loses full visibility into what is happening in the environment."},{id:"bp-3",difficulty:"advanced",question:"Design a minimal interface for an IDE bridge. What operations would it need to expose, and what properties should those operations have?",hint:"Think about what an agent needs to understand and manipulate code.",solution:"A minimal IDE bridge interface would expose: read file contents (given a path), write file contents, list directory structure, execute a command and return output, get cursor or selection position, and open/navigate to a location. Each operation should be synchronous from the agent's perspective, return explicit errors rather than silently failing, and avoid side-channel state that would make the bridge's behavior unpredictable."}]})]})}const k=Object.freeze(Object.defineProperty({__proto__:null,default:r},Symbol.toStringTag,{value:"Module"}));function l(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"Permission Delegation"}),e.jsx("p",{children:"An IDE integration gives an agent access to sensitive resources: source code, configuration files, terminal commands, and build systems. Deciding what the agent is allowed to do — and who decides — is one of the most important design questions in IDE integration."}),e.jsx(t,{title:"Permission Delegation",number:"Concept 11.2",children:"Permission delegation is the mechanism by which a human operator grants the agent a scoped set of capabilities within their environment. The human retains ultimate authority but temporarily delegates specific rights — such as read access to a directory, or the ability to run tests — to the agent for the duration of a task."}),e.jsxs("p",{children:["The key word is ",e.jsx("em",{children:"scoped"}),". Granting an agent total access to everything in the environment is almost never necessary and carries real risk. Instead, the agent should receive only the permissions required for the current task. A code review agent needs read access; it does not need write access. A test runner needs to execute tests; it does not need to modify source files."]}),e.jsx(a,{title:"Ambient Authority is Dangerous",children:"When an agent automatically inherits all the permissions of the user who launched it, this is called ambient authority. It means the agent can do anything the user can do — delete production data, push to main, or send emails. Most tasks require far less than this. Scoping permissions explicitly prevents accidental or malicious overreach."}),e.jsx(n,{title:"Delegation Is Revocable",type:"note",children:"Good permission systems allow the operator to revoke delegated rights at any time — not just at the end of a task. If the agent's behavior becomes unexpected, the human should be able to instantly withdraw access without waiting for the task to complete. Revocability is a critical safety property."}),e.jsx(i,{title:"Exercises",exercises:[{id:"pd-1",difficulty:"beginner",question:"What is the principle of least privilege and why does it apply directly to IDE integrations?",hint:'Think about what "minimum necessary access" means in the context of code and files.',solution:"The principle of least privilege states that a system should be granted only the minimum permissions required to accomplish its current task. In IDE integrations, this means an agent should not automatically have access to every file, command, and service available to the developer. Scoped permissions reduce the blast radius if the agent makes a mistake or behaves unexpectedly — it cannot damage what it cannot access."},{id:"pd-2",difficulty:"intermediate",question:"A developer launches an agent to write documentation for a module. List the permissions the agent needs and the permissions it explicitly should not have.",hint:"Map the task to its actual resource requirements.",solution:"The agent needs: read access to the source files in the target module, write access to the documentation output location, and perhaps read access to existing docs for style reference. It should not have: write access to source files, terminal execution rights, access to secrets or environment variables, access to other modules, or network access. The task is documentation — nothing else is required."},{id:"pd-3",difficulty:"advanced",question:"How should a permission system handle an agent that requests additional permissions mid-task because it discovers the original scope was insufficient?",hint:"Think about trust, transparency, and the human in the loop.",solution:"The agent should surface a clear, explicit request explaining what additional permission it needs and why. The human then decides whether to grant it. The agent should not acquire additional access silently or work around the scope limit. This creates an auditable trail of what the agent accessed and provides the human with checkpoints for oversight. The system should make these requests easy to understand and approve or deny."}]})]})}const T=Object.freeze(Object.defineProperty({__proto__:null,default:l},Symbol.toStringTag,{value:"Module"}));function c(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"Inline vs. External Agents"}),e.jsx("p",{children:"There are two fundamental ways an agent can be positioned relative to the IDE: running inside it as a first-class extension, or running outside it as a separate process that interacts with the IDE through an API. Each model has trade-offs that shape what the agent can see, do, and how it should be designed."}),e.jsx(t,{title:"Inline Agent",number:"Concept 11.3",children:"An inline agent runs within the IDE process itself, often as a plugin or extension. It has direct access to the IDE's internal APIs — the abstract syntax tree, the language server, open editor state, and cursor position. Its integration is tight and its latency is low, but it is bound to a specific host environment and update cycle."}),e.jsx(t,{title:"External Agent",number:"Concept 11.4",children:"An external agent runs as a separate process and communicates with the IDE through a defined protocol — typically a local server, a file-watching mechanism, or an extension that acts as a relay. It is more portable and easier to test in isolation, but the communication boundary introduces latency and limits what the agent can observe."}),e.jsx("p",{children:"The choice between inline and external often comes down to the richness of context required. Tasks that need real-time awareness of editor state — completing the current line, suggesting a refactor for the highlighted selection — benefit from inline access. Tasks that operate on the project as a whole — analyzing the entire codebase, running test suites, managing dependencies — are well-served by an external agent."}),e.jsx(o,{title:"Match Coupling to Task Scope",number:"Principle 11.1",children:"The tightness of an agent's integration with its host environment should match the scope of the tasks it performs. Tight coupling brings rich context but reduces portability. Loose coupling brings portability but narrows perception. Neither is universally superior — choose based on the tasks the agent actually needs to do."}),e.jsx(n,{title:"Hybrid Architectures",type:"note",children:"Many production IDE integrations use both patterns together: a lightweight inline extension captures rich editor context and streams it to an external agent process that does the heavy reasoning. This separates the concerns of perception (inline) from reasoning and action (external), giving both portability and rich context."}),e.jsx(i,{title:"Exercises",exercises:[{id:"ie-1",difficulty:"beginner",question:"Name two tasks that are better suited to an inline agent and two tasks better suited to an external agent. Explain why for each.",hint:"Think about what context each task needs and how quickly it needs to respond.",solution:"Inline: (1) Autocomplete — needs cursor position and surrounding context instantly, latency matters. (2) Hover documentation — needs access to the language server's type information in real time. External: (1) Whole-codebase refactoring — needs to read many files, can tolerate latency, should be tested independently. (2) Dependency auditing — reads package manifests and calls external registries, no need for editor state."},{id:"ie-2",difficulty:"intermediate",question:"What are the testing implications of inline vs. external agent architectures? Which is easier to test, and why?",hint:"Consider what you need to have running to test each type.",solution:"External agents are far easier to test because they are independent processes with a well-defined interface. Tests can mock the IDE side of the communication boundary without launching an actual IDE. Inline agents require either a running IDE instance or a complex test harness that simulates the IDE's internal APIs. This makes inline agents slower to develop, harder to regression-test, and more fragile when the host IDE changes its internal structure."},{id:"ie-3",difficulty:"advanced",question:"In a hybrid architecture where an inline extension feeds context to an external agent, what protocol design decisions matter most? What could go wrong at the boundary?",hint:"Think about serialization, freshness, and ordering of events.",solution:"Key decisions: (1) Serialization format — context must be efficiently serialized to minimize latency. (2) Freshness — the agent must know whether the context it received is stale; rapid edits can produce many events and the agent must handle or discard out-of-date snapshots. (3) Ordering — events from the editor must arrive in order; dropped or reordered events produce incorrect context. (4) Cancellation — if the user changes their intent before the agent responds, the prior request must be cancelled cleanly."}]})]})}const j=Object.freeze(Object.defineProperty({__proto__:null,default:c},Symbol.toStringTag,{value:"Module"}));function d(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"Interactive Sessions"}),e.jsx("p",{children:"An IDE agent rarely completes its work in a single isolated burst. More often, it operates in an interactive session — a continuous loop where the developer and the agent exchange messages, the agent takes actions, and the developer can redirect, approve, or interrupt at any point. Designing for interactive sessions requires thinking carefully about state, interruption, and shared understanding."}),e.jsx(t,{title:"Interactive Session",number:"Concept 11.5",children:"An interactive session is a stateful, multi-turn exchange between the developer and the agent within the IDE. The agent accumulates context across turns — prior messages, actions taken, files modified — and uses it to inform each next step. Sessions can be paused, redirected, or terminated by the developer at any time."}),e.jsx(s,{title:"The Pair Programming Session",children:"Think of an interactive agent session like pair programming with a colleague. You describe what you want to accomplish, they start making changes, you give feedback mid-stream, they adjust. The session has a shared context — both of you know what has already been done. If you get interrupted and come back later, you both need to re-establish that shared understanding before continuing."}),e.jsx("p",{children:"Session state is the accumulated record of what has happened: what the agent was asked to do, what it did, what it observed, and what the developer said in response. This state must be maintained faithfully because the agent's next action depends on it. Losing session state mid-task — due to a crash, timeout, or restart — forces the agent to act without history, which is dangerous."}),e.jsx(a,{title:"Never Assume Continuity",children:"An agent should never assume that a session will run to completion without interruption. Developers close their IDE, switch tasks, or lose network connections. A well-designed interactive session should be resumable: the agent stores enough state that it can reconstruct where it left off, and it confirms with the developer before continuing rather than blindly picking up where it stopped."}),e.jsx(i,{title:"Exercises",exercises:[{id:"is-1",difficulty:"beginner",question:"What information would you store in session state to allow an interrupted agent session to be resumed accurately?",hint:"Think about what the agent knew, what it did, and what it was about to do.",solution:"Session state should store: the original task description, the conversation history (all messages exchanged), a list of actions taken (files modified, commands run) with their results, the current plan or next intended step, and any context the developer provided mid-session. With this, the agent can give the developer a clear summary of where things stand and ask whether to continue, modify, or abandon the task."},{id:"is-2",difficulty:"intermediate",question:'A developer redirects an agent mid-task: "Actually, ignore what I said about tests — focus on the UI first." How should the agent handle this redirect?',hint:"Consider both immediate response and the impact on session state.",solution:"The agent should: (1) acknowledge the redirect clearly, (2) summarize what it has already done for the tests (so the developer knows the current state), (3) ask whether those test changes should be kept or reverted, and (4) then shift focus to the UI. The session state must be updated to reflect the new priority. Silently switching focus without acknowledgment risks the developer losing track of what state the codebase is in."},{id:"is-3",difficulty:"advanced",question:'How does the concept of "undo" complicate interactive agent sessions, and what design choices make undo more tractable?',hint:"Think about compound actions — what happens when a single agent turn involves many file changes?",solution:"Each agent turn may involve many discrete actions (editing multiple files, running commands with side effects). Undoing a turn means reversing all of those actions atomically. This requires the agent to track every change it makes with enough detail to reverse it, and to recognize that some actions (network calls, file deletions without backup) may be irreversible. Design choices that help: taking snapshots before each turn, treating all changes as staged until explicitly committed, presenting the diff to the developer before applying, and avoiding irreversible side effects whenever possible."}]})]})}const A=Object.freeze(Object.defineProperty({__proto__:null,default:d},Symbol.toStringTag,{value:"Module"}));function h(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"Remote Machines"}),e.jsx("p",{children:"Agents do not always run on the same machine as the developer or the user who invoked them. In many real-world deployments, an agent runs on a remote server — a cloud instance, a compute node, or a shared development environment. This changes the operational model significantly."}),e.jsx(t,{title:"Remote Agent Execution",number:"Concept 11.6",children:`Remote execution means the agent process runs on a machine that is not the local developer workstation. The agent operates in that remote environment — reading files, running commands, and accessing services — but communicates its outputs back to the human across a network boundary. The agent's perspective of "local" is the remote machine, not the developer's laptop.`}),e.jsx("p",{children:"Remote execution is often chosen for resource reasons — the remote machine has more CPU, more memory, or access to private networks that the local machine does not. It is also used for isolation: running untrusted code or large-scale operations on a dedicated machine prevents interference with the developer's local environment."}),e.jsx(n,{title:"Latency Is Now a First-Class Concern",type:"note",children:"Every action the agent takes on the remote machine involves a round-trip over the network. File reads, command outputs, and status updates all travel across this boundary. Designing agents for remote execution means accounting for latency at every step — batching operations where possible, streaming outputs incrementally, and avoiding unnecessary round-trips."}),e.jsx(a,{title:"Environment Drift",children:"The remote machine's environment may differ from what the agent expects: different software versions, different file system layouts, different environment variables. Agents running remotely must be resilient to these differences and should inspect their environment before making assumptions rather than trusting that the remote setup matches a template."}),e.jsx(i,{title:"Exercises",exercises:[{id:"rm-1",difficulty:"beginner",question:"List three reasons why you might prefer to run an agent on a remote machine rather than locally. List one significant downside of each.",hint:"Consider resources, isolation, and network access.",solution:"(1) More compute — the remote machine has more CPU/RAM for intensive tasks. Downside: latency for all I/O. (2) Isolation — agent runs in a sandboxed environment away from local files. Downside: harder to debug; agent cannot easily access local artifacts. (3) Private network access — the remote machine is inside a VPC with access to internal services. Downside: security surface increases; credentials for those services must be safely provided to the agent."},{id:"rm-2",difficulty:"intermediate",question:"An agent running remotely needs to process 500 files. How should it approach this differently than if it were running locally?",hint:"Think about how many round-trips are needed and how to minimize them.",solution:"On a remote machine, the agent should process files locally (on the remote server) rather than streaming each file back to the orchestrator for processing. It should batch operations — reading many files in one call if possible — rather than making one call per file. Results should be aggregated and returned as a summary rather than streamed as individual outputs. The key principle is to minimize the number of times data crosses the network boundary."},{id:"rm-3",difficulty:"advanced",question:"What happens when a remote agent process is killed mid-task? Design a recovery strategy that allows the agent to resume safely.",hint:"Think about checkpointing, idempotency, and how to communicate the agent's prior state.",solution:"The agent should write checkpoints to persistent storage at meaningful milestones — after completing each logical sub-task. Each operation should be idempotent where possible: re-running the same step should produce the same result, not a duplicate. On restart, the agent reads the last checkpoint, informs the human of the recovery, and asks whether to resume from that point. Actions that cannot be made idempotent (e.g., sending a notification) should be guarded with completion flags stored alongside the checkpoint."}]})]})}const I=Object.freeze(Object.defineProperty({__proto__:null,default:h},Symbol.toStringTag,{value:"Module"}));function u(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"Secure Tunneling"}),e.jsx("p",{children:"When an agent operates on a remote machine, every message between the agent and its orchestrator — including instructions, tool results, and sensitive outputs — travels across a network. That network must be treated as untrusted. Secure tunneling is the mechanism that protects this communication."}),e.jsx(t,{title:"Secure Tunnel",number:"Concept 11.7",children:"A secure tunnel is an encrypted, authenticated channel between two endpoints. It ensures that messages cannot be read by third parties (confidentiality), cannot be tampered with in transit (integrity), and originate from the expected sender (authenticity). For agents, a secure tunnel protects both instructions going to the agent and outputs coming back."}),e.jsx("p",{children:"The threat model for agent communication is not hypothetical. Instructions sent in plaintext can be observed and modified. An adversary who can inject or alter messages in the communication channel between an orchestrator and an agent can effectively redirect the agent's behavior — causing it to take actions that were never authorized by the human operator."}),e.jsx(o,{title:"Treat Every Network as Untrusted",number:"Principle 11.2",children:'An agent should never send sensitive data over an unencrypted channel, even within a "private" network. Internal networks can be compromised, cloud VPCs can be misconfigured, and co-located services can be malicious. End-to-end encryption from orchestrator to agent is the only reliable way to ensure the communication channel has not been subverted.'}),e.jsx(a,{title:"Credential Exposure in Transit",children:"Agent instructions often contain credentials, API keys, or tokens needed to perform tasks. If these travel over an unencrypted channel, they are exposed to anyone who can observe the network. This is not a theoretical risk — leaked credentials are one of the most common causes of security incidents. Always encrypt the channel before sending any sensitive material."}),e.jsx(i,{title:"Exercises",exercises:[{id:"st-1",difficulty:"beginner",question:"What are the three properties a secure tunnel provides? Why does each matter for agent communication specifically?",hint:"Consider what happens if each property is absent.",solution:'Confidentiality ensures that sensitive instructions, credentials, and outputs cannot be read by a third party intercepting the traffic. Integrity ensures that messages cannot be silently altered — an attacker cannot change "delete test files" to "delete all files." Authenticity ensures the agent is actually talking to its intended orchestrator and not an impersonator injecting rogue instructions. All three matter because agents act on their instructions directly, so a compromised channel means compromised behavior.'},{id:"st-2",difficulty:"intermediate",question:"An agent needs to connect to a remote machine that is behind a firewall with no public IP address. Describe a tunneling approach that would allow this without opening public ports.",hint:"Think about which side initiates the connection.",solution:'The remote machine can initiate an outbound connection to a relay server (or directly to the orchestrator if it is reachable). Because the connection is outbound, no inbound port needs to be opened through the firewall. This is commonly implemented as a persistent WebSocket or gRPC connection that the agent maintains. The orchestrator sends instructions as messages over this existing connection. This is sometimes called "reverse tunneling" — the agent reaches out rather than waiting to be reached.'},{id:"st-3",difficulty:"advanced",question:"How should an agent respond if its secure tunnel drops mid-task? What behaviors are acceptable and what would be dangerous?",hint:"Think about partial completion, side effects already taken, and the risk of resuming without the orchestrator's knowledge.",solution:"Acceptable behaviors: pause all new actions immediately, store current state to persistent storage, attempt to re-establish the tunnel with exponential backoff, and resume only after the orchestrator explicitly re-authorizes continuation (not automatically). Dangerous behaviors: continuing to take actions without the orchestrator's awareness (the human can no longer observe or intervene), silently discarding completed work, or retrying failed actions without checking whether they already succeeded (risking double execution of destructive operations)."}]})]})}const P=Object.freeze(Object.defineProperty({__proto__:null,default:u},Symbol.toStringTag,{value:"Module"}));function g(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"Message Translation"}),e.jsx("p",{children:"When an agent operates across a network boundary, its messages rarely travel in the exact format the remote environment expects. Different systems speak different protocols, use different data formats, and have different expectations about message structure. Message translation is the process of bridging these gaps."}),e.jsx(t,{title:"Message Translation Layer",number:"Concept 11.8",children:"A message translation layer converts messages from one format or protocol to another as they cross a boundary between systems. For remote agent integrations, this layer sits between the agent's abstract tool calls and the concrete API or protocol that the remote environment understands. It serializes, deserializes, adapts schemas, and handles version differences."}),e.jsx(s,{title:"The Power Adapter",children:"When you travel internationally, your devices use the same internal components, but the wall socket is different in every country. You use a power adapter — a thin layer that translates the socket's format into what your device expects. A message translation layer works the same way: both systems continue to operate using their native formats; the adapter handles the conversion at the boundary."}),e.jsx("p",{children:"Without a translation layer, agent integrations become fragile. Hardcoding the remote system's wire format into the agent's logic couples them tightly — when the remote system changes its API, the agent must change too. A dedicated translation layer isolates this change to one place."}),e.jsx(n,{title:"Schema Evolution",type:"note",children:"Remote systems evolve their APIs over time. A message that was valid last month may fail today. The translation layer should be versioned and capable of handling multiple API versions simultaneously during migration. It should also degrade gracefully: if a field is missing from the remote response, it should use a sensible default rather than crashing the agent."}),e.jsx(i,{title:"Exercises",exercises:[{id:"mt-1",difficulty:"beginner",question:"Why is it better to put message translation in a dedicated layer rather than handling it directly in the agent's reasoning logic?",hint:"Think about what happens when the remote system changes its format.",solution:"If the agent handles translation directly, any change to the remote system's format requires changing the agent. This conflates two distinct concerns: the agent's job is to reason and take actions, not to know the byte layout of a remote API. A dedicated translation layer means API changes are absorbed in one place, the agent stays stable, and the translation logic can be tested independently without running the full agent."},{id:"mt-2",difficulty:"intermediate",question:"A remote tool returns a response in a format the translation layer does not recognize — a field has been renamed in a new API version. What should the translation layer do?",hint:"Consider both the immediate response and how the agent should be informed.",solution:"The translation layer should: (1) attempt to identify the response version from metadata or structural hints, (2) map the new field name to the expected internal name if the mapping is deterministic, (3) if unable to translate, return a clear structured error to the agent explaining that the response format was unrecognized, not a garbled partial result. The agent can then decide whether to retry, ask the user, or report the issue. Silent partial translation is worse than a clear failure."},{id:"mt-3",difficulty:"advanced",question:"Design a versioning strategy for a message translation layer that must support two active API versions simultaneously during a migration period.",hint:"Think about how to identify which version to use and how to route messages.",solution:"The layer should use version negotiation: on connection establishment, the remote system declares which API versions it supports and the translation layer selects the highest mutually supported version. Each inbound and outbound message carries a version tag. The layer maintains separate translation modules for each supported version and routes messages to the appropriate module. Deprecation warnings are surfaced as structured metadata. Once the old version is unsupported by all remote endpoints, its translation module is removed."}]})]})}const q=Object.freeze(Object.defineProperty({__proto__:null,default:g},Symbol.toStringTag,{value:"Module"}));function p(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"Cross-Machine Coordination"}),e.jsx("p",{children:"Some agent tasks span more than one remote machine. A deployment pipeline might involve a build server, a test cluster, and a production host. A data processing task might coordinate work across multiple compute nodes. Cross-machine coordination is the art of keeping agents on different machines working together correctly."}),e.jsx(t,{title:"Cross-Machine Coordination",number:"Concept 11.9",children:"Cross-machine coordination refers to the mechanisms that allow multiple agent processes — running on different machines — to work toward a shared goal without conflicting. It involves dividing work, communicating state, handling partial failures, and agreeing on what has been completed so that the overall task progresses correctly."}),e.jsx("p",{children:"The central challenge is that distributed systems have no shared clock and no instantaneous communication. One machine may complete its portion of the work while another has not yet started. Messages may arrive out of order. A machine may fail silently, leaving its assigned work incomplete with no notification. Coordination protocols must be designed to handle these realities."}),e.jsx(o,{title:"Design for Partial Failure",number:"Principle 11.3",children:"In cross-machine agent systems, any individual machine can fail at any time. A coordination design that assumes all machines will complete their work is not a design — it is a wish. Every workflow must have a defined answer to: what happens if this step does not complete? Can it be retried? Reassigned? Skipped? Partial failure is not an edge case; it is the normal operating condition."}),e.jsx(a,{title:"Beware of Split-Brain",children:"A split-brain scenario occurs when two machines each believe they are the authoritative coordinator for the same task. Both may take conflicting actions — writing different results, triggering the same downstream step twice, or overwriting each other's work. Coordination protocols must include a mechanism for resolving authority, such as distributed locks or a single designated coordinator machine."}),e.jsx(i,{title:"Exercises",exercises:[{id:"cm-1",difficulty:"beginner",question:`Why can't you simply rely on each machine in a multi-machine agent system to report "done" and then proceed? What can go wrong?`,hint:"Think about network failures, silent crashes, and message loss.",solution:'A machine can fail after completing its work but before sending its "done" message. Or the "done" message can be lost in transit. Or the machine can appear to complete but have silently produced incorrect output. Relying on self-reported completion without verification means a single lost message or silent failure can stall or corrupt the entire workflow. Robust coordination requires acknowledgment receipts, idempotent retries, and independent verification where possible.'},{id:"cm-2",difficulty:"intermediate",question:"An agent is coordinating a task across three machines. Machine B completes its work, but Machine A fails partway through. How should the coordinator handle this?",hint:"Consider whether Machine B's work needs to be undone and how to restart Machine A.",solution:"The coordinator should: (1) detect the failure via a heartbeat timeout or explicit error message, (2) assess whether Machine B's completed work depends on Machine A's completion — if so, it may need to be held or rolled back, (3) attempt to restart or reassign Machine A's work to another machine, (4) once Machine A's work is completed, verify that the combined outputs are consistent before proceeding. The key is that incomplete partial work should never be treated as final."},{id:"cm-3",difficulty:"advanced",question:"How does idempotency help with cross-machine coordination, and what makes a task idempotent in this context?",hint:"Think about what happens when you safely retry a step that may have already completed.",solution:'Idempotency means running a step multiple times produces the same result as running it once. In cross-machine coordination, this allows safe retries: if a machine fails, you can simply restart its task on another machine without risk of duplicating effects. A task is idempotent if it checks for prior completion before acting (e.g., "has this record already been processed?"), produces the same output for the same input regardless of how many times it runs, and avoids side effects that accumulate with repeated execution (such as appending to a log rather than setting a value).'}]})]})}const E=Object.freeze(Object.defineProperty({__proto__:null,default:p},Symbol.toStringTag,{value:"Module"}));function m(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"Plugin Architecture"}),e.jsx("p",{children:"No agent can be built with every capability it will ever need at design time. Domains evolve, user needs vary, and new integrations emerge constantly. A plugin architecture allows an agent to grow its capabilities over time without requiring changes to its core."}),e.jsx(t,{title:"Plugin Architecture",number:"Concept 11.10",children:"A plugin architecture is a design pattern in which a core system provides a stable interface for external modules — plugins — to attach additional behavior. The core does not need to know what plugins exist at design time. Plugins conform to a defined contract, and the core loads and orchestrates them dynamically. The agent's capabilities become a function of which plugins are present."}),e.jsx(s,{title:"The Swiss Army Knife",children:"A Swiss Army knife has a fixed handle and a set of attachment slots. Each attachment — blade, scissors, screwdriver — plugs into the same slot using the same connection mechanism. You can swap attachments in and out, add new ones that did not exist when the knife was made, or carry only the ones you need. The handle never changes; the capabilities do. A plugin architecture works exactly the same way."}),e.jsx("p",{children:"The contract between the core agent and its plugins is called the plugin interface. This interface defines what operations a plugin must implement, how it declares its capabilities, and how it receives and returns data. A well-designed plugin interface is stable across versions — plugins written today should continue to work even as the core agent evolves."}),e.jsx(o,{title:"Core Stability, Plugin Flexibility",number:"Principle 11.4",children:"The core agent should change rarely and carefully. Plugins should change freely. This means the plugin interface must be designed conservatively — erring on the side of simplicity and generality — because any change to the interface breaks all existing plugins. Stability in the core enables an ecosystem of plugins to grow around it."}),e.jsx(i,{title:"Exercises",exercises:[{id:"pa-1",difficulty:"beginner",question:"What problems does a plugin architecture solve compared to building all capabilities directly into the core agent?",hint:"Think about change, deployment, and the variety of user needs.",solution:"Without plugins, adding new capabilities requires modifying and redeploying the core agent. Every user gets every capability, including ones they do not need. Experimental or domain-specific features are mixed with stable core behavior. With plugins, capabilities are added independently without touching the core, users load only what they need, and risky or experimental features can be isolated in plugins with limited blast radius if they malfunction."},{id:"pa-2",difficulty:"intermediate",question:"What properties should a plugin interface have to remain stable over time while still allowing new capabilities to be expressed?",hint:"Think about backward compatibility, versioning, and extension points.",solution:"A stable plugin interface should use explicit versioning so plugins can declare compatibility. New capabilities should be added through opt-in extension points rather than required fields — plugins that do not implement an extension simply do not gain that capability. Required interface methods should be minimal and general. The core should ignore unknown fields from plugins rather than failing. Over time, old interface versions should be deprecated gradually with a sunset timeline rather than removed abruptly."},{id:"pa-3",difficulty:"advanced",question:"Two plugins both attempt to handle the same kind of event. How should the core agent resolve this conflict? What are the trade-offs of different resolution strategies?",hint:"Consider priority-based, first-match, and broadcast approaches.",solution:"Three main strategies: (1) Priority-based — plugins declare a priority; the highest-priority handler wins. Simple, but can be fragile if priorities conflict or create unexpected overrides. (2) First-match — the first plugin registered that claims to handle the event is used. Predictable for simple cases but dependent on load order. (3) Broadcast — all interested plugins handle the event independently; results are merged or all applied. Flexible but risks conflicting side effects. The best choice depends on the semantics: for mutually exclusive actions (e.g., responding to a query), priority or first-match is appropriate; for notifications (e.g., logging), broadcast is natural."}]})]})}const D=Object.freeze(Object.defineProperty({__proto__:null,default:m},Symbol.toStringTag,{value:"Module"}));function f(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"Plugin Discovery and Loading"}),e.jsx("p",{children:"Before a plugin can extend an agent's capabilities, the agent must find it and bring it into operation. This process — discovery and loading — involves locating available plugins, validating them, and initializing them in a way that is both safe and predictable."}),e.jsx(t,{title:"Plugin Discovery",number:"Concept 11.11",children:"Plugin discovery is the mechanism by which the core agent learns what plugins are available. Discovery can be static — a configuration file lists the plugins to load — or dynamic — the agent scans a directory, queries a registry, or responds to runtime announcements. Each approach trades flexibility against predictability and security."}),e.jsx("p",{children:"Static discovery is simpler and more auditable: the operator explicitly lists which plugins are active, and nothing else loads. Dynamic discovery is more flexible but requires the agent to evaluate untrusted sources — a directory that could contain anything, or a registry that could be compromised. The discovery mechanism is a security boundary, not just an engineering convenience."}),e.jsx(n,{title:"Load Order Matters",type:"note",children:"Plugins are often loaded in a specific order, and some plugins may depend on others being initialized first. The loading system must handle dependencies between plugins — ensuring that if Plugin B requires Plugin A, Plugin A is loaded and initialized before Plugin B's initialization begins. Circular dependencies must be detected and rejected at load time, not discovered at runtime when they cause infinite loops."}),e.jsx(a,{title:"Never Load Untrusted Plugins Automatically",children:"A plugin that loads automatically gains full access to the agent's plugin interface, including any sensitive capabilities it exposes. Automatically loading plugins from untrusted sources — such as arbitrary directories or public registries without verification — is a significant security risk. Plugins should be explicitly authorized by the operator before they are allowed to load."}),e.jsx(i,{title:"Exercises",exercises:[{id:"dl-1",difficulty:"beginner",question:"What is the difference between static and dynamic plugin discovery? When would you prefer each?",hint:"Think about control, predictability, and flexibility.",solution:"Static discovery reads a fixed configuration list — the operator explicitly specifies which plugins are active. It is predictable, auditable, and safe: only listed plugins load. Dynamic discovery scans for plugins at runtime based on rules like directory scanning. It is flexible — plugins can be added without reconfiguring — but introduces risk because unknown plugins may load. Prefer static discovery for production deployments where stability and security matter; dynamic discovery is useful during development when plugins change frequently."},{id:"dl-2",difficulty:"intermediate",question:"A plugin fails to initialize — it throws an error during its setup phase. What should the loading system do? Should it continue loading other plugins or abort entirely?",hint:"Consider what the plugin provides and whether other plugins or the core depends on it.",solution:"The loading system should distinguish between critical and optional plugins. For critical plugins (required by the core or by other plugins), initialization failure should abort loading entirely and surface a clear error — continuing without a critical dependency is dangerous. For optional plugins, the error should be logged clearly and loading should continue without that plugin. Users should be informed that a plugin failed to load. The system should never silently suppress plugin initialization errors."},{id:"dl-3",difficulty:"advanced",question:"Design a plugin verification process that ensures a plugin is safe to load before it runs any code. What checks would you perform?",hint:"Think about both the plugin's identity and its behavior before it executes.",solution:"Before loading: (1) Cryptographic signature verification — the plugin must be signed by a known trusted key; unsigned plugins are rejected. (2) Manifest validation — the plugin declares its capabilities, permissions, and dependencies; the manifest is checked for completeness and compatibility with the current core version. (3) Dependency resolution — all declared dependencies are present and at compatible versions. (4) Sandbox pre-check — the plugin's declared capabilities are compared against the permissions the operator has granted. At runtime: (5) The plugin runs in a sandbox with only the capabilities it declared; any attempt to use undeclared capabilities fails explicitly."}]})]})}const C=Object.freeze(Object.defineProperty({__proto__:null,default:f},Symbol.toStringTag,{value:"Module"}));function y(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"How Plugins Add Capabilities"}),e.jsx("p",{children:"Plugins extend an agent in specific ways defined by the plugin interface. The most common extensions are new tools, new knowledge sources, and new behaviors for handling particular kinds of requests. Understanding how these extensions work helps both plugin authors and agent designers build systems that compose well."}),e.jsx(t,{title:"Capability Extension",number:"Concept 11.12",children:"A plugin extends agent capabilities by registering new handlers with the core. A tool plugin registers a new callable action — the agent can now invoke it. A knowledge plugin registers a new retrieval source — the agent can now query it. A behavior plugin registers a new response pattern for specific request types. In each case, the extension is additive: the core's existing capabilities remain intact and the new capability augments them."}),e.jsx("p",{children:"The key design principle behind additive extension is that plugins should not need to modify the core to add their capabilities. If a plugin must reach into the core and change its behavior to function, the plugin interface is poorly designed. A well-designed interface provides clean hooks that plugins attach to without touching core logic."}),e.jsx(s,{title:"The Electrical Outlet",children:"Plugging a lamp into the wall does not change the house's wiring. The electrical system provides a standard socket; the lamp connects to it and gains access to power. The house does not need to know what kind of lamp will be plugged in — it only needs to provide the right outlet interface. Capability extension works the same way: the agent provides the socket; the plugin brings the lamp."}),e.jsx(n,{title:"Composing Plugins",type:"tip",children:"Plugins that each add a single focused capability compose well: an agent with ten focused plugins is predictable and debuggable. Plugins that try to do many things or that override broad swaths of agent behavior compose poorly — they conflict with each other and with the core in ways that are hard to anticipate. Plugin design benefits from the same single-responsibility thinking that applies to tools and agents generally."}),e.jsx(i,{title:"Exercises",exercises:[{id:"pc-1",difficulty:"beginner",question:"What are three different types of capabilities a plugin might add to an agent? Give a concrete example of each.",hint:"Think about tools, knowledge, and behavior patterns.",solution:"(1) New tool: a weather plugin that adds a get_weather action the agent can call when answering questions about conditions. (2) New knowledge source: a documentation plugin that registers a retrieval function allowing the agent to search an internal wiki. (3) New behavior: a formatting plugin that intercepts code-related responses and adds syntax highlighting, changing how the agent presents certain outputs."},{id:"pc-2",difficulty:"intermediate",question:"Why is it important that plugins add capabilities additively rather than modifying the core? What goes wrong when plugins patch core behavior directly?",hint:"Think about multiple plugins interacting and debugging.",solution:"When plugins modify core behavior directly, their changes interact unpredictably. Plugin A patches function X; Plugin B also patches function X; the result depends on load order and is not what either plugin intended. Debugging is nearly impossible because the source of unexpected behavior is hidden inside patches. Additive extension avoids this: each plugin adds to a defined registry without touching shared code. The core's behavior remains stable regardless of which plugins are loaded."},{id:"pc-3",difficulty:"advanced",question:"A plugin wants to add a capability that requires modifying how the agent formats all its responses. How should this be handled in a well-designed plugin architecture?",hint:'Think about hooks, middleware, and whether "all responses" is the right scope.',solution:"The plugin interface should provide a response-processing hook — a middleware layer that plugins can register into. This hook is called for each response and plugins in the chain can transform it. This is additive: the plugin adds itself to the processing chain without modifying core response logic. The agent developer must design this hook explicitly; if no hook exists, the plugin author should request it as a core extension rather than patching the core themselves. Additionally, the plugin should scope its transformation narrowly — applying it only to response types where it is appropriate, not truly to all responses."}]})]})}const S=Object.freeze(Object.defineProperty({__proto__:null,default:y},Symbol.toStringTag,{value:"Module"}));function b(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"Plugin Lifecycle"}),e.jsx("p",{children:"A plugin is not simply loaded and left running indefinitely. It moves through a series of states from discovery to deactivation, and managing these transitions correctly is essential for a stable and safe agent system."}),e.jsx(t,{title:"Plugin Lifecycle",number:"Concept 11.13",children:"The plugin lifecycle describes the sequence of states a plugin passes through: discovery, validation, initialization, active operation, deactivation, and unloading. Each transition has defined entry conditions and actions the system must take. A plugin that skips steps — going directly from loading to active operation without proper initialization — is a source of subtle and hard-to-diagnose bugs."}),e.jsx("p",{children:"The most important transitions are initialization and deactivation. Initialization is where the plugin sets up its state, connects to external services, and registers its capabilities with the core. Deactivation is where it cleans up: closing connections, releasing resources, and unregistering its capabilities. A plugin that does not deactivate cleanly leaves the agent in a degraded state — orphaned connections, registered capabilities that no longer function, or leaked memory."}),e.jsx(o,{title:"Clean Deactivation Is Not Optional",number:"Principle 11.5",children:"Every plugin must have a defined deactivation procedure that runs when the plugin is removed, the agent is shutting down, or an error forces the plugin offline. Deactivation is not an edge case to implement later — it is as important as initialization. A system that handles startup but not shutdown will accumulate damage over time."}),e.jsx(n,{title:"Hot Reloading",type:"tip",children:"In some environments, plugins can be updated and reloaded without restarting the entire agent. This is called hot reloading. It requires that the deactivation of the old version and the initialization of the new version happen atomically from the agent's perspective — with no window where neither version is active and requests fail. Hot reloading is powerful but requires careful lifecycle management to avoid race conditions."}),e.jsx(i,{title:"Exercises",exercises:[{id:"pl-1",difficulty:"beginner",question:"List the stages of a plugin lifecycle and describe what the agent system should do at each transition.",hint:"Think about discovery, initialization, active state, and shutdown.",solution:"Discovery: agent finds the plugin and reads its manifest. Validation: manifest is checked for compatibility and signature is verified. Initialization: plugin's setup code runs, resources are acquired, capabilities are registered. Active: plugin handles events and provides capabilities normally. Deactivation: capabilities are unregistered, in-flight requests are completed or rejected gracefully, resources are released. Unloading: the plugin's memory and handles are fully removed from the agent process."},{id:"pl-2",difficulty:"intermediate",question:"A plugin is deactivated while it is in the middle of handling a long-running operation. How should this be managed?",hint:"Think about in-flight work and the options for handling it.",solution:"The deactivation process should first signal the plugin to stop accepting new work. Any in-flight operations can either be allowed to complete within a defined timeout (graceful shutdown) or cancelled with a structured error returned to the caller. The choice depends on the operation type: operations with visible side effects (writing files, sending messages) should complete if possible. After the timeout or completion, the plugin cleans up remaining resources. The caller must receive a clear error for any cancelled operation rather than silence."},{id:"pl-3",difficulty:"advanced",question:"Design a versioning strategy for a plugin that allows the agent to upgrade the plugin from v1 to v2 without dropping any in-flight requests.",hint:"Think about running both versions simultaneously during the transition.",solution:"Use a blue-green approach: initialize the new (v2) plugin before deactivating the old (v1) plugin. Route all new incoming requests to v2. Allow v1 to continue handling its in-flight requests until they complete or time out. Once v1 has no active requests, deactivate it. This requires the capability registration system to support multiple versions of the same plugin simultaneously with request routing logic. The handoff window should be bounded by a maximum timeout after which v1 is forcefully deactivated and its remaining requests are cancelled."}]})]})}const M=Object.freeze(Object.defineProperty({__proto__:null,default:b},Symbol.toStringTag,{value:"Module"}));export{k as a,T as b,j as c,A as d,I as e,P as f,q as g,E as h,D as i,C as j,S as k,M as l,x as s};
